import type { SyntaxNodeRef } from '@lezer/common';

import type { FilterFieldProps } from '../../../../FilterField.types.js';
import type { ConvertedLezerNode } from '../../../../types/conversion-utils.js';
import type {
  FilterFieldErrorNode,
  FilterFieldJSONPathNode,
} from '../../../../types/tree-nodes.js';
import { getTextFromRange } from '../../../get-text.js';
import { removeEscapeCharacters } from '../../escape-characters.js';
import { updateNodeValues } from '../node-mutations.js';
import { convertIdentifier } from '../value/identifier.js';

/**
 * Convert a jsonpath node.
 * @internal
 */
export function convertJsonPath(
  node: SyntaxNodeRef,
  doc: string,
  parserConfig?: FilterFieldProps['parserConfig'],
): ConvertedLezerNode<FilterFieldErrorNode | FilterFieldJSONPathNode> {
  const { from, to } = node;
  const cursor = node.node.cursor();

  let convertedNode: FilterFieldErrorNode | FilterFieldJSONPathNode = {
    type: 'Error',
    range: {
      from,
      to,
    },
    textValue: '',
    value: '',
  };
  const errors: { range: { from: number; to: number }; message: string }[] = [];

  const {
    convertedNode: { textValue, value },
  } = convertIdentifier(node, doc);

  // For JSONPath, both textValue and value are the same to be able to correctly
  // convert it in the tree to string conversion.
  updateNodeValues(convertedNode, textValue, textValue);
  let isValidJsonPath = true;

  // eslint-disable-next-line @typescript-eslint/no-deprecated
  if (parserConfig?.jsonPathConversion) {
    convertedNode = {
      ...convertedNode,
      type: 'JSONPath',
    } as FilterFieldJSONPathNode;

    let path = '$';
    let pushToPath = false;

    cursor.iterate(
      (jsonPathChildNode) => {
        const nodeName = jsonPathChildNode.name;

        if (nodeName === 'JsonPathBase') {
          const text = getTextFromRange(jsonPathChildNode, doc);
          // Remove trailing $ and all escape characters.
          const cleanedUpRoot = removeEscapeCharacters(
            text
              .slice(0, -1) // Remove leading and trailing doublequote if it is not escaped.
              // Properly escaped backslashes are preserved with the capturing group and the backreference.
              .replace(/^"(.*(?<=^|[^\\])(?:\\\\)*)"$/, '$1'),
          );

          (convertedNode as FilterFieldJSONPathNode).root = cleanedUpRoot;
          return;
        }

        if (!pushToPath) {
          return;
        }

        if (
          nodeName === 'JsonPathIdentifier' ||
          nodeName === 'JsonPathArray' ||
          nodeName === 'String' ||
          nodeName === 'JsonPathNameSelector'
        ) {
          const text = getTextFromRange(jsonPathChildNode, doc);

          // add the current node to the path based on its type
          // to create a valid JSONPath
          switch (nodeName) {
            case 'JsonPathIdentifier':
              path += `.${text}`;
              break;
            case 'JsonPathArray':
              path += `${text}`;
              break;
            case 'String':
              path += `[${text}]`;
              break;
          }
        }

        // An error node may occur here if the JSONPath is invalid (e.g. a$.[0]).
        if (nodeName === '⚠') {
          isValidJsonPath = false;
        }
      },
      (node) => {
        if (node.name === 'JsonPathBase') {
          pushToPath = true;
        }
      },
    );

    convertedNode.path = path;
  }

  // eslint-disable-next-line @typescript-eslint/no-deprecated
  if (!parserConfig?.jsonPathConversion || !isValidJsonPath) {
    convertedNode = {
      type: 'Error',
      range: convertedNode.range,
      value,
      textValue,
    };
    errors.push({ range: { from, to }, message: 'invalidKey' });
  }

  return { convertedNode, errors };
}
